update survey_questionnaire
status = #{status}, published_time = #{publishedTime}, ended_time = #{endedTime}, update_by = #{updateBy}, update_time = #{updateTime}
where questionnaire_id = #{questionnaireId} and del_flag = '0'
and status = #{currentStatus}

